INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('pukao-6f0ba476-moex-00269', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '依民法規定，約定週年利率一旦逾下列何者，債務人得於1年後隨時清償原本？', '["5%", "12%", "18%", "20%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00270', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', 'A 商品為市場上流通之種類物，而甲在自己並未取得任何 A 商品之情形，與乙訂立 A 商品之買 賣契約、並約定由甲運送交付予乙。締約後，甲為準備對乙履約，乃向丙購得A商品，並將其置 放於甲自身之B倉庫內，卻於交付A商品予乙前，B倉庫因甲管理不慎失火，致B倉庫內商品 全部滅失。下列敘述，何者正確？', '["履行期屆至前，甲仍另須在市場上購入相同種類之A商品，以履行對乙所負之債務", "甲將自丙購入之A商品置放於B倉庫時，該批商品即為特定給付物", "甲有可歸責事由造成標的物滅失，為給付不能，乙僅得向甲請求損害賠償", "甲、乙締約時，甲未取得A商品，乃自始不能，該契約無效"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00271', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '關於給付不能之代償請求權的適用範圍及其法律效果，下列敘述，何者錯誤？', '["因不可歸責於贈與人之給付不能，受贈人得向贈與人主張代償請求權", "因可歸責於債務人之事由致給付不能時，債權人得不請求民法第226條損害賠償而類推適用同 法第225條第2項行使代償請求權", "民法第225條第2項之賠償物的價額超過原給付標的之價值時，債權人得請求超過原給付利益 之代償利益", "第225條第2項之代償請求權不包括原給付標的滅失之損害賠償"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00272', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '物權乃其效力及於任何人之權利。下列何者並非物權？', '["租賃權", "典權", "債權質權", "所有權"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00273', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲、乙結婚後育有丙子。丙5歲時，甲、乙離婚，約定由乙單獨任丙之親權人，甲每個月給付丙 新臺幣10,000元之扶養費。5年後，甲與丁結婚，育有雙胞胎戊子、己子。甲主張自己已有新家 庭，且收入不足負擔3個小孩之扶養費，故拒絕再提供丙扶養費，有無理由？', '["有理由，因甲與丙之親子關係及扶養義務，會隨甲再婚而育有新子女而消滅", "有理由，因甲係戊、己之親權人，卻非丙之親權人", "無理由，因甲對於丙之扶養義務，不因甲離婚或再婚而受影響", "無理由，當甲之收入不足以負擔全部子女之扶養費時，應優先負擔前婚子女之費用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00274', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲乙為夫妻，生有獨子丙。甲死亡時，丙5歲。乙依法聲請法院指定甲之父戊為特別代理人，代 理丙與乙訂立遺產分割協議。該協議之效力為何？', '["有效", "無效", "得撤銷", "效力未定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00275', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '甲喪妻，有子女乙、丙、丁三人，丁有一子戊。甲因丁營業而贈與其新臺幣（下同）300萬元。但 丁早於甲死亡。甲死亡時，留有現金900萬元。戊得繼承甲之遺產為多少？', '["0元", "100萬元", "300萬元", "400萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00276', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於死亡宣告之敘述，何者正確？', '["得聲請死亡宣告之主體為利害關係人或檢察官", "81歲之甲某日外出買菜後即失蹤、遍尋不著，得於失蹤滿1年後，為死亡之宣告", "受死亡宣告者，以裁判內所確定死亡之時，推定其為死亡。故死亡宣告之時點，不得舉反證推翻", "82歲之乙不幸遭遇特別災難而失蹤時，應於特別災難終了滿3年後，為死亡之宣告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00277', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於契約關係之消滅時效之敘述，何者錯誤？', '["時效完成後，債務人縱不知該請求權時效已完成，然既經以契約承諾其債務，亦不得以不知時效 為由，拒絕履行該契約", "請求權已經時效消滅，債務人仍為契約之履行者，不得以不知時效為理由，請求返還", "依契約承認其債務，除須兩造意思表示互相一致外，其方式應以書面為之", "債務人於時效完成後，就其債務，與債權人約定另一給付期或為分期給付，可認已拋棄時效利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00278', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-a7c7609b', 'sub-pukao-6f0ba476-02', NULL, 'single_choice', '下列關於表見代理之敘述，何者錯誤？', '["事實行為不得成立代理，自無表見代理之適用", "受託保管他人支票及其印章，竟盜蓋印章並以本人名義簽發支票之行為，應有表見代理之適用", "結婚之身分行為，不得成立表見代理", "債權讓與行為較諸一般法律行為更注重要式及外觀，故債權讓與行為不得成立表見代理"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "8643edec57b1", "answer_pdf_sha1": "2783db52ca84", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "1105", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
